1	type Listener = (...args: unknown[]) => void;
2	
3	export class EventEmitter {
4	  // Implement: on(event, listener) - register listener, return unsubscribe function
5	  on(event: string, listener: Listener): () => void {
6	    throw new Error("Not implemented");
7	  }
8	
9	  // Implement: once(event, listener) - listener fires only once
10	  once(event: string, listener: Listener): void {
11	    throw new Error("Not implemented");
12	  }
13	
14	  // Implement: emit(event, ...args) - call all listeners, return true if any existed
15	  emit(event: string, ...args: unknown[]): boolean {
16	    throw new Error("Not implemented");
17	  }
18	
19	  // Implement: off(event, listener) - remove specific listener
20	  off(event: string, listener: Listener): void {
21	    throw new Error("Not implemented");
22	  }
23	
24	  // Implement: removeAllListeners(event?) - remove all or per-event
25	  removeAllListeners(event?: string): void {
26	    throw new Error("Not implemented");
27	  }
28	
29	  // Implement: listenerCount(event) - return count
30	  listenerCount(event: string): number {
31	    throw new Error("Not implemented");
32	  }
