4	describe("EventEmitter", () => {
5	  // -------------------------------------------------------
6	  // Basic on / emit
7	  // -------------------------------------------------------
8	  describe("on and emit", () => {
9	    it("should register a listener and call it on emit", () => {
10	      const emitter = new EventEmitter();
11	      const fn = vi.fn();
12	
13	      emitter.on("data", fn);
14	      emitter.emit("data", 42);
15	
16	      expect(fn).toHaveBeenCalledWith(42);
17	      expect(fn).toHaveBeenCalledTimes(1);
18	    });
19	
20	    it("should pass multiple arguments to listener", () => {
21	      const emitter = new EventEmitter();
22	      const fn = vi.fn();
23	
24	      emitter.on("multi", fn);
25	      emitter.emit("multi", "a", "b", "c");
26	
27	      expect(fn).toHaveBeenCalledWith("a", "b", "c");
28	    });
29	
30	    it("should call listener on every emit", () => {
31	      const emitter = new EventEmitter();
32	      const fn = vi.fn();
33	
34	      emitter.on("ping", fn);
35	      emitter.emit("ping");
36	      emitter.emit("ping");
37	      emitter.emit("ping");
38	
39	      expect(fn).toHaveBeenCalledTimes(3);
40	    });
41	  });
42	
43	  // -------------------------------------------------------
44	  // Multiple listeners on same event
45	  // -------------------------------------------------------
46	  describe("multiple listeners on same event", () => {
47	    it("should call all listeners for an event", () => {
48	      const emitter = new EventEmitter();
49	      const fn1 = vi.fn();
50	      const fn2 = vi.fn();
51	      const fn3 = vi.fn();
52	
53	      emitter.on("event", fn1);
54	      emitter.on("event", fn2);
55	      emitter.on("event", fn3);
56	      emitter.emit("event", "hello");
57	
58	      expect(fn1).toHaveBeenCalledWith("hello");
59	      expect(fn2).toHaveBeenCalledWith("hello");
60	      expect(fn3).toHaveBeenCalledWith("hello");
61	    });
62	  });
63	
64	  // -------------------------------------------------------
65	  // Multiple events
66	  // -------------------------------------------------------
67	  describe("multiple events", () => {
68	    it("should keep listeners separate per event", () => {
69	      const emitter = new EventEmitter();
70	      const fnA = vi.fn();
71	      const fnB = vi.fn();
72	
73	      emitter.on("a", fnA);
74	      emitter.on("b", fnB);
75	      emitter.emit("a", 1);
76	
77	      expect(fnA).toHaveBeenCalledWith(1);
78	      expect(fnB).not.toHaveBeenCalled();
79	    });
80	  });
81	
82	  // -------------------------------------------------------
83	  // once
84	  // -------------------------------------------------------
85	  describe("once", () => {
86	    it("should fire listener only once", () => {
87	      const emitter = new EventEmitter();
88	      const fn = vi.fn();
89	
90	      emitter.once("login", fn);
91	      emitter.emit("login", "user1");
92	      emitter.emit("login", "user2");
93	
94	      expect(fn).toHaveBeenCalledTimes(1);
95	      expect(fn).toHaveBeenCalledWith("user1");
96	    });
97	
98	    it("should not affect other listeners on the same event", () => {
99	      const emitter = new EventEmitter();
100	      const onceFn = vi.fn();
101	      const alwaysFn = vi.fn();
102	
103	      emitter.once("msg", onceFn);
104	      emitter.on("msg", alwaysFn);
105	      emitter.emit("msg", "first");
106	      emitter.emit("msg", "second");
107	
108	      expect(onceFn).toHaveBeenCalledTimes(1);
109	      expect(alwaysFn).toHaveBeenCalledTimes(2);
110	    });
111	  });
112	
113	  // -------------------------------------------------------
114	  // off
115	  // -------------------------------------------------------
116	  describe("off", () => {
117	    it("should remove a specific listener", () => {
118	      const emitter = new EventEmitter();
119	      const fn = vi.fn();
120	
121	      emitter.on("x", fn);
122	      emitter.off("x", fn);
123	      emitter.emit("x");
124	
125	      expect(fn).not.toHaveBeenCalled();
126	    });
127	
128	    it("should not throw when removing a non-existent listener", () => {
129	      const emitter = new EventEmitter();
130	      const fn = vi.fn();
131	
132	      expect(() => emitter.off("nope", fn)).not.toThrow();
133	    });
134	
135	    it("should not throw when removing from a non-existent event", () => {
136	      const emitter = new EventEmitter();
137	
138	      expect(() => emitter.off("ghost", () => {})).not.toThrow();
139	    });
140	
141	    it("should only remove the specified listener", () => {
142	      const emitter = new EventEmitter();
143	      const fn1 = vi.fn();
144	      const fn2 = vi.fn();
145	
146	      emitter.on("e", fn1);
147	      emitter.on("e", fn2);
148	      emitter.off("e", fn1);
149	      emitter.emit("e");
150	
151	      expect(fn1).not.toHaveBeenCalled();
152	      expect(fn2).toHaveBeenCalledTimes(1);
153	    });
154	  });
155	
156	  // -------------------------------------------------------
157	  // Unsubscribe function returned by on()
158	  // -------------------------------------------------------
159	  describe("unsubscribe function from on()", () => {
160	    it("should unsubscribe the listener when called", () => {
161	      const emitter = new EventEmitter();
162	      const fn = vi.fn();
163	
164	      const unsub = emitter.on("tick", fn);
165	      emitter.emit("tick");
166	      expect(fn).toHaveBeenCalledTimes(1);
167	
168	      unsub();
169	      emitter.emit("tick");
170	      expect(fn).toHaveBeenCalledTimes(1);
171	    });
172	
173	    it("should not affect other listeners when called", () => {
174	      const emitter = new EventEmitter();
175	      const fn1 = vi.fn();
176	      const fn2 = vi.fn();
177	
178	      const unsub = emitter.on("tick", fn1);
179	      emitter.on("tick", fn2);
180	
181	      unsub();
182	      emitter.emit("tick");
183	
184	      expect(fn1).not.toHaveBeenCalled();
185	      expect(fn2).toHaveBeenCalledTimes(1);
186	    });
187	  });
188	
189	  // -------------------------------------------------------
190	  // removeAllListeners
191	  // -------------------------------------------------------
192	  describe("removeAllListeners", () => {
193	    it("should remove all listeners for all events when no arg given", () => {
194	      const emitter = new EventEmitter();
195	      const fn1 = vi.fn();
196	      const fn2 = vi.fn();
197	
198	      emitter.on("a", fn1);
199	      emitter.on("b", fn2);
200	      emitter.removeAllListeners();
201	      emitter.emit("a");
202	      emitter.emit("b");
203	
204	      expect(fn1).not.toHaveBeenCalled();
205	      expect(fn2).not.toHaveBeenCalled();
206	    });
207	
208	    it("should remove listeners only for the specified event", () => {
209	      const emitter = new EventEmitter();
210	      const fnA = vi.fn();
211	      const fnB = vi.fn();
212	
213	      emitter.on("a", fnA);
214	      emitter.on("b", fnB);
215	      emitter.removeAllListeners("a");
216	      emitter.emit("a");
217	      emitter.emit("b");
218	
219	      expect(fnA).not.toHaveBeenCalled();
220	      expect(fnB).toHaveBeenCalledTimes(1);
221	    });
222	  });
223	
224	  // -------------------------------------------------------
225	  // listenerCount
226	  // -------------------------------------------------------
227	  describe("listenerCount", () => {
228	    it("should return 0 for unknown event", () => {
229	      const emitter = new EventEmitter();
230	      expect(emitter.listenerCount("none")).toBe(0);
231	    });
232	
233	    it("should return correct count after adding listeners", () => {
234	      const emitter = new EventEmitter();
235	      emitter.on("x", () => {});
236	      emitter.on("x", () => {});
237	      emitter.on("x", () => {});
238	
239	      expect(emitter.listenerCount("x")).toBe(3);
240	    });
241	
242	    it("should decrease after off", () => {
243	      const emitter = new EventEmitter();
244	      const fn = () => {};
245	      emitter.on("x", fn);
246	      emitter.on("x", () => {});
247	
248	      expect(emitter.listenerCount("x")).toBe(2);
249	      emitter.off("x", fn);
250	      expect(emitter.listenerCount("x")).toBe(1);
251	    });
252	
253	    it("should decrease after once listener fires", () => {
254	      const emitter = new EventEmitter();
255	      emitter.once("x", () => {});
256	      emitter.on("x", () => {});
257	
258	      expect(emitter.listenerCount("x")).toBe(2);
259	      emitter.emit("x");
260	      expect(emitter.listenerCount("x")).toBe(1);
261	    });
262	  });
263	
264	  // -------------------------------------------------------
265	  // eventNames
266	  // -------------------------------------------------------
267	  describe("eventNames", () => {
268	    it("should return empty array when no listeners registered", () => {
269	      const emitter = new EventEmitter();
270	      expect(emitter.eventNames()).toEqual([]);
271	    });
272	
273	    it("should return event names that have listeners", () => {
274	      const emitter = new EventEmitter();
275	      emitter.on("foo", () => {});
276	      emitter.on("bar", () => {});
277	      emitter.on("baz", () => {});
278	
279	      const names = emitter.eventNames();
280	      expect(names).toContain("foo");
281	      expect(names).toContain("bar");
282	      expect(names).toContain("baz");
283	      expect(names).toHaveLength(3);
284	    });
285	
286	    it("should not include events after all their listeners are removed", () => {
287	      const emitter = new EventEmitter();
288	      const fn = () => {};
289	      emitter.on("temp", fn);
290	      emitter.off("temp", fn);
291	
292	      expect(emitter.eventNames()).not.toContain("temp");
293	    });
294	  });
295	
296	  // -------------------------------------------------------
297	  // emit return value
298	  // -------------------------------------------------------
299	  describe("emit return value", () => {
300	    it("should return false when no listeners exist", () => {
301	      const emitter = new EventEmitter();
302	      expect(emitter.emit("nothing")).toBe(false);
303	    });
304	
305	    it("should return true when listeners exist", () => {
306	      const emitter = new EventEmitter();
307	      emitter.on("something", () => {});
308	      expect(emitter.emit("something")).toBe(true);
309	    });
310	
311	    it("should return true even if the only listener was a once that just fired", () => {
312	      const emitter = new EventEmitter();
313	      emitter.once("one-shot", () => {});
314	
315	      // First emit: the once listener is present => true
316	      expect(emitter.emit("one-shot")).toBe(true);
317	      // Second emit: no listeners left => false
318	      expect(emitter.emit("one-shot")).toBe(false);
319	    });
320	  });
321	
322	  // -------------------------------------------------------
323	  // Listener invocation order
324	  // -------------------------------------------------------
325	  describe("listener invocation order", () => {
326	    it("should call listeners in registration order", () => {
327	      const emitter = new EventEmitter();
328	      const order: number[] = [];
329	
330	      emitter.on("order", () => order.push(1));
331	      emitter.on("order", () => order.push(2));
332	      emitter.on("order", () => order.push(3));
333	      emitter.emit("order");
334	
335	      expect(order).toEqual([1, 2, 3]);
336	    });
337	  });
338	
339	  // -------------------------------------------------------
340	  // Listener removes itself during emit (no crash)
341	  // -------------------------------------------------------
342	  describe("self-removal during emit", () => {
343	    it("should not crash when a listener removes itself during emit", () => {
344	      const emitter = new EventEmitter();
345	      const results: string[] = [];
346	
347	      const selfRemover = () => {
348	        results.push("self-remover");
349	        emitter.off("evt", selfRemover);
350	      };
351	
352	      emitter.on("evt", selfRemover);
353	      emitter.on("evt", () => results.push("after"));
354	
355	      expect(() => emitter.emit("evt")).not.toThrow();
356	      expect(results).toEqual(["self-remover", "after"]);
357	    });
358	
359	    it("should not call a listener that was removed by an earlier listener during the same emit", () => {
360	      const emitter = new EventEmitter();
361	      const results: string[] = [];
362	      const victim = () => results.push("victim");
363	
364	      emitter.on("evt", () => {
365	        results.push("killer");
366	        emitter.off("evt", victim);
367	      });
368	      emitter.on("evt", victim);
369	
370	      emitter.emit("evt");
371	
372	      // The victim was registered after killer, but killer removed it during emit.
373	      // Whether victim runs or not depends on implementation — both are acceptable.
374	      // The key requirement is: no crash.
375	      expect(results).toContain("killer");
376	    });
377	
378	    it("should handle unsubscribe function used during emit", () => {
379	      const emitter = new EventEmitter();
380	      const results: string[] = [];
381	      let unsub: () => void;
382	
383	      unsub = emitter.on("evt", () => {
384	        results.push("will-unsub");
385	        unsub();
386	      });
387	      emitter.on("evt", () => results.push("second"));
388	
389	      expect(() => emitter.emit("evt")).not.toThrow();
390	      expect(results).toContain("will-unsub");
391	      expect(results).toContain("second");
392	    });
393	  });
394	});
