type Listener = (...args: unknown[]) => void;

export class EventEmitter {
  private listeners = new Map<string, Listener[]>();

  // Register listener, return unsubscribe function
  on(event: string, listener: Listener): () => void {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, []);
    }
    this.listeners.get(event)!.push(listener);
    return () => this.off(event, listener);
  }

  // Listener fires only once
  once(event: string, listener: Listener): void {
    const wrapper: Listener = (...args: unknown[]) => {
      this.off(event, wrapper);
      listener(...args);
    };
    this.on(event, wrapper);
  }

  // Call all listeners, return true if any existed
  emit(event: string, ...args: unknown[]): boolean {
    const handlers = this.listeners.get(event);
    if (!handlers || handlers.length === 0) {
      return false;
    }
    // Snapshot to avoid issues when listeners remove themselves during iteration
    const snapshot = [...handlers];
    for (const handler of snapshot) {
      handler(...args);
    }
    return true;
  }

  // Remove specific listener
  off(event: string, listener: Listener): void {
    const handlers = this.listeners.get(event);
    if (!handlers) return;
    const index = handlers.indexOf(listener);
    if (index !== -1) {
      handlers.splice(index, 1);
    }
    if (handlers.length === 0) {
      this.listeners.delete(event);
    }
  }

  // Remove all or per-event
  removeAllListeners(event?: string): void {
    if (event !== undefined) {
      this.listeners.delete(event);
    } else {
      this.listeners.clear();
    }
  }

  // Return count
  listenerCount(event: string): number {
    const handlers = this.listeners.get(event);
    return handlers ? handlers.length : 0;
  }

  // Return array of events with listeners
  eventNames(): string[] {
    return [...this.listeners.keys()];
  }
}

